import{_ as t,o as r,c as a,ae as o}from"./chunks/framework.CylwKCfq.js";const p=JSON.parse('{"title":"🌐 Use TrustIn Explorer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/layer1-product.md","filePath":"guide/layer1-product.md"}'),n={name:"guide/layer1-product.md"};function i(s,e,l,d,h,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🌐-use-trustin-explorer" tabindex="-1">🌐 Use TrustIn Explorer <a class="header-anchor" href="#🌐-use-trustin-explorer" aria-label="Permalink to &quot;🌐 Use TrustIn Explorer&quot;">​</a></h1><p>The fastest way to trace blockchain transactions — no setup, no API key, no code.</p><h2 id="what-is-trustin-explorer" tabindex="-1">What is TrustIn Explorer? <a class="header-anchor" href="#what-is-trustin-explorer" aria-label="Permalink to &quot;What is TrustIn Explorer?&quot;">​</a></h2><p><a href="https://v2.trustin.info/explore" target="_blank" rel="noreferrer">TrustIn Explorer</a> is a full-featured AML (Anti-Money Laundering) investigation platform. It provides:</p><ul><li><strong>Visual transaction graph</strong> — trace fund flows across Ethereum and Tron</li><li><strong>Risk scoring</strong> — AI-powered risk assessment for every address</li><li><strong>Entity tagging</strong> — identify exchanges, mixers, sanctioned addresses</li><li><strong>Multi-hop tracing</strong> — follow funds through multiple hops</li><li><strong>Inflow &amp; outflow analysis</strong> — see where funds came from and where they went</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><ol><li>Visit <a href="https://v2.trustin.info/explore" target="_blank" rel="noreferrer">v2.trustin.info</a></li><li>Enter a blockchain address (Ethereum or Tron)</li><li>Select direction: <strong>Inflow</strong> / <strong>Outflow</strong> / <strong>Both</strong></li><li>Click <strong>Explore</strong> — the graph loads instantly</li></ol><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="risk-levels" tabindex="-1">Risk Levels <a class="header-anchor" href="#risk-levels" aria-label="Permalink to &quot;Risk Levels&quot;">​</a></h3><p>Each node (address) is colored by risk:</p><table tabindex="0"><thead><tr><th>Color</th><th>Risk Level</th><th>Meaning</th></tr></thead><tbody><tr><td>🔴 Red</td><td>High</td><td>Sanctioned, dark market, mixer</td></tr><tr><td>🟡 Yellow</td><td>Medium</td><td>Suspicious patterns detected</td></tr><tr><td>🟢 Green</td><td>Low</td><td>Verified exchange, known entity</td></tr><tr><td>⚫ Gray</td><td>Unknown</td><td>No data available</td></tr></tbody></table><h3 id="expanding-the-graph" tabindex="-1">Expanding the Graph <a class="header-anchor" href="#expanding-the-graph" aria-label="Permalink to &quot;Expanding the Graph&quot;">​</a></h3><ul><li>Click any node to see its details</li><li>Click the <strong>+</strong> button on a node to expand its connections</li><li>Right-click a node to remove it from the view</li></ul><h3 id="renderer-modes" tabindex="-1">Renderer Modes <a class="header-anchor" href="#renderer-modes" aria-label="Permalink to &quot;Renderer Modes&quot;">​</a></h3><p>Switch between two renderers:</p><ul><li><strong>ReactFlow</strong> — best for interactive exploration, drag nodes, zoom</li><li><strong>Sigma.js</strong> — best for large graphs (1000+ nodes), WebGL-accelerated</li></ul><h2 id="when-to-use-trustin-explorer" tabindex="-1">When to use TrustIn Explorer <a class="header-anchor" href="#when-to-use-trustin-explorer" aria-label="Permalink to &quot;When to use TrustIn Explorer&quot;">​</a></h2><p>✅ Quick investigation — need an answer now<br> ✅ No technical setup required<br> ✅ Full feature set including AI risk scoring<br> ✅ Regular compliance checks</p><p>→ For programmatic access or embedding in your own app, see <a href="/txgraph/guide/layer2-demo.html">Layer 2: Run Demo Locally</a> or <a href="/txgraph/guide/layer3-component.html">Layer 3: Build Your Own</a>.</p>',19)])])}const g=t(n,[["render",i]]);export{p as __pageData,g as default};
